import{m as l,aU as a,z as i,M as o}from"./chunks/framework.LN92DB6A.js";const t=JSON.parse('{"title":"广州社保查询与办事指南：参保证明、转移、缴费基数","description":"社保每月都在交，但怎么查、怎么用、断了怎么办？本文整理广州社保查询、转移、灵活就业参保等常用操作。","frontmatter":{"title":"广州社保查询与办事指南：参保证明、转移、缴费基数","tags":["广州","社保","参保证明","社保转移","灵活就业","五险"],"categories":["办事攻略"],"date":"2026-05-29T00:00:00.000Z","description":"社保每月都在交，但怎么查、怎么用、断了怎么办？本文整理广州社保查询、转移、灵活就业参保等常用操作。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/social-security"}]]},"headers":[],"relativePath":"posts/2026/social-security.md","filePath":"posts/2026/social-security.md","lastUpdated":1779868425000}');const r=l({name:"posts/2026/social-security.md"},[["render",function(l,t,r,e,s,n){return a(),i("div",null,[...t[0]||(t[0]=[o('<p>社保每个月都在扣钱，但很多人对自己的社保账户一无所知——交了多少年、账户里有多少钱、断了怎么办。其实查社保、办转移、打证明，现在线上都能搞定。</p><h2 id="广州社保五险速览" tabindex="-1">广州社保五险速览 <a class="header-anchor" href="#广州社保五险速览" aria-label="Permalink to &quot;广州社保五险速览&quot;">​</a></h2><p>广州职工社保包含五险，每月由单位和个人共同缴纳：</p><ul><li><strong>养老保险</strong>：退休后领养老金，累计缴满15年可领</li><li><strong>医疗保险</strong>：看病报销，包含个人账户（有钱可用）和统筹账户（报销用）</li><li><strong>失业保险</strong>：非自愿失业后可领失业金，缴满1年以上</li><li><strong>工伤保险</strong>：工作中受伤可报销，个人不用交</li><li><strong>生育保险</strong>：产检、分娩报销+生育津贴，已并入医保</li></ul><h2 id="怎么查社保" tabindex="-1">怎么查社保 <a class="header-anchor" href="#怎么查社保" aria-label="Permalink to &quot;怎么查社保&quot;">​</a></h2><h3 id="方式一-粤省事小程序-推荐" tabindex="-1">方式一：粤省事小程序（推荐） <a class="header-anchor" href="#方式一-粤省事小程序-推荐" aria-label="Permalink to &quot;方式一：粤省事小程序（推荐）&quot;">​</a></h3><ol><li>微信搜索**&quot;粤省事&quot;**小程序</li><li>登录后搜索**&quot;社保&quot;**</li><li>可以查到：缴费明细、参保状态、个人账户余额等</li></ol><h3 id="方式二-穗好办app" tabindex="-1">方式二：穗好办APP <a class="header-anchor" href="#方式二-穗好办app" aria-label="Permalink to &quot;方式二：穗好办APP&quot;">​</a></h3><ol><li>下载**&quot;穗好办&quot;**APP</li><li>注册登录后进入**&quot;社保&quot;**板块</li><li>支持查询、打印参保证明等</li></ol><h3 id="方式三-广东省人社厅网上服务平台" tabindex="-1">方式三：广东省人社厅网上服务平台 <a class="header-anchor" href="#方式三-广东省人社厅网上服务平台" aria-label="Permalink to &quot;方式三：广东省人社厅网上服务平台&quot;">​</a></h3><ul><li>网址：hrss.gd.gov.cn</li><li>电脑端操作，功能更全</li></ul><h3 id="方式四-12333热线" tabindex="-1">方式四：12333热线 <a class="header-anchor" href="#方式四-12333热线" aria-label="Permalink to &quot;方式四：12333热线&quot;">​</a></h3><ul><li>拨打<strong>12333</strong>，按语音提示操作</li><li>适合不会用手机操作的老年人</li></ul><h2 id="参保证明怎么开" tabindex="-1">参保证明怎么开 <a class="header-anchor" href="#参保证明怎么开" aria-label="Permalink to &quot;参保证明怎么开&quot;">​</a></h2><p>入职新公司、办居住证、子女入学、申请贷款，经常需要用到参保证明。</p><h3 id="线上开具-推荐" tabindex="-1">线上开具（推荐） <a class="header-anchor" href="#线上开具-推荐" aria-label="Permalink to &quot;线上开具（推荐）&quot;">​</a></h3><ol><li>打开**&quot;粤省事&quot;**小程序</li><li>搜索**&quot;参保证明&quot;**</li><li>选择需要的险种和时间段</li><li>生成电子版，可下载打印</li></ol><h3 id="线下开具" tabindex="-1">线下开具 <a class="header-anchor" href="#线下开具" aria-label="Permalink to &quot;线下开具&quot;">​</a></h3><ul><li>到各区<strong>社保经办机构</strong>窗口</li><li>携带身份证，在自助终端机或窗口打印</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>参保证明一般需要显示连续缴费记录。如果中间有断缴，证明上会体现出来。办居住证、积分入学等对连续缴费有要求的业务，提前确认自己的缴费记录是否完整。</p></div><h2 id="社保转移" tabindex="-1">社保转移 <a class="header-anchor" href="#社保转移" aria-label="Permalink to &quot;社保转移&quot;">​</a></h2><p>从外地来广州工作，或者从广州去其他城市，社保可以转移接续。</p><h3 id="从外地转入广州" tabindex="-1">从外地转入广州 <a class="header-anchor" href="#从外地转入广州" aria-label="Permalink to &quot;从外地转入广州&quot;">​</a></h3><ol><li>在广州参保后，到<strong>国家社保公共服务平台</strong>（si.12333.gov.cn）申请转移</li><li>或通过**&quot;粤省事&quot;**小程序 → 搜索&quot;社保转移&quot;</li><li>提交转入申请，系统自动向原参保地发起联系函</li><li>原参保地办理转出，资金划转至广州账户</li><li>广州社保局完成接续</li></ol><h3 id="从广州转出" tabindex="-1">从广州转出 <a class="header-anchor" href="#从广州转出" aria-label="Permalink to &quot;从广州转出&quot;">​</a></h3><ol><li>在新参保地申请转入</li><li>新参保地发起联系函，广州社保局收到后办理转出</li><li>养老保险个人账户资金全额转移，统筹部分按比例转移</li></ol><h3 id="转移注意事项" tabindex="-1">转移注意事项 <a class="header-anchor" href="#转移注意事项" aria-label="Permalink to &quot;转移注意事项&quot;">​</a></h3><ul><li>养老保险、医疗保险都可以转移</li><li>失业保险一般不转移，在新参保地重新计算</li><li>转移没有时间限制，但建议尽早办理，避免材料遗失</li><li>省内转移一般更简单，部分已实现自动接续</li></ul><h2 id="灵活就业参保" tabindex="-1">灵活就业参保 <a class="header-anchor" href="#灵活就业参保" aria-label="Permalink to &quot;灵活就业参保&quot;">​</a></h2><p>自由职业者、离职期间不想社保断缴的，可以以<strong>灵活就业人员</strong>身份自己参保。</p><h3 id="可参保险种" tabindex="-1">可参保险种 <a class="header-anchor" href="#可参保险种" aria-label="Permalink to &quot;可参保险种&quot;">​</a></h3><ul><li><strong>养老保险</strong>：可选</li><li><strong>医疗保险</strong>：可选</li></ul><p>工伤、失业、生育保险需要通过单位缴纳，灵活就业人员不能单独参加。</p><h3 id="办理方式" tabindex="-1">办理方式 <a class="header-anchor" href="#办理方式" aria-label="Permalink to &quot;办理方式&quot;">​</a></h3><ol><li><strong>线上</strong>：通过&quot;穗好办&quot;APP或&quot;粤省事&quot;小程序办理参保/停保</li><li><strong>线下</strong>：到户籍所在地或居住地的社保经办机构办理</li></ol><h3 id="缴费基数" tabindex="-1">缴费基数 <a class="header-anchor" href="#缴费基数" aria-label="Permalink to &quot;缴费基数&quot;">​</a></h3><ul><li>可在上下限范围内自主选择缴费基数</li><li>基数每年7月调整一次</li><li>缴费比例：养老20%，医疗按当地标准</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>灵活就业参保的费用全部由个人承担，没有单位分担部分。按最低基数缴纳，每月也需要一千多元。离职前算好自己的经济承受能力。</p></div><h2 id="断缴有什么影响" tabindex="-1">断缴有什么影响 <a class="header-anchor" href="#断缴有什么影响" aria-label="Permalink to &quot;断缴有什么影响&quot;">​</a></h2><p>社保断缴的影响比你想的大：</p><ul><li><strong>医保</strong>：断缴次月起不能享受医保报销（个人账户余额还能用）</li><li><strong>养老保险</strong>：累计满15年即可，断缴不影响已缴年限，但会减少退休金</li><li><strong>生育保险</strong>：分娩前需连续缴满一定月数才能享受报销和津贴</li><li><strong>购房/入户资格</strong>：广州购房、积分入户等都要求连续社保年限</li><li><strong>居住证签注</strong>：需要就业证明，社保记录是重要佐证</li></ul><h3 id="补缴政策" tabindex="-1">补缴政策 <a class="header-anchor" href="#补缴政策" aria-label="Permalink to &quot;补缴政策&quot;">​</a></h3><ul><li>单位原因导致的断缴，可由单位申请补缴</li><li>个人原因的断缴，一般不能补缴（政策收紧后限制较多）</li><li>灵活就业人员断缴后重新参保，从缴费次月起恢复待遇</li></ul><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>离职后医保别断</strong>：如果离职后短期内不打算入职新公司，及时转为灵活就业参保，确保医保不断</li><li><strong>社保转移别拖太久</strong>：虽然没有时间限制，但拖久了原单位可能注销、材料可能丢失</li><li><strong>不要找代缴公司挂靠</strong>：市面上的&quot;社保代缴&quot;服务，通过虚构劳动关系参保属于违规行为，查实后可能被清退缴费年限</li><li><strong>每年查一次社保记录</strong>：确保单位如实缴纳，有疑问及时向单位或社保局反映</li><li><strong>灵活就业参保要及时</strong>：离职后尽快办理，避免出现断缴空白期</li><li><strong>缴费基数影响退休金</strong>：经济允许的话，尽量选择较高的缴费基数</li></ul><p>社保是咱们最重要的保障之一，别等用到的时候才发现有问题。定期查看自己的缴费记录，有断缴及时处理。</p>',46)])])}]]);export{t as __pageData,r as default};
